glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
#if USE_TEXTURE
in vec2 a_uv0;
out vec2 v_uv0;
#endif
void main () {
  vec4 pos = vec4(a_position, 1);
  #if CC_USE_MODEL
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  pos = cc_matViewProj * pos;
  #endif
  #if USE_TEXTURE
  v_uv0 = a_uv0;
  #endif
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
in vec4 v_color;
#if USE_TEXTURE
in vec2 v_uv0;
uniform sampler2D texture;
#endif
uniform PROPERTIES {
  lowp float x;
  lowp float y;
  lowp float z;
  lowp float w;
  lowp float rotated;
  lowp float whratio;
  lowp float r;
  lowp float g;
  lowp float b;
  lowp float a;
  lowp float doblend;
  lowp float startx;
  mediump float angle;
  mediump float width;
  mediump float strength;
};
void main()
{
  vec4 uvOffset = vec4(x, y, z, w);
  vec4 outColor = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
  vec4 texture_tmp = texture(texture, v_uv0);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, v_uv0 + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    outColor.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    outColor.a *= texture_tmp.a;
  #else
    outColor *= texture_tmp;
  #endif
  #endif
  outColor = doblend > 0.5 ? vec4(r, g, b, a) : outColor;
  float uv0X = (v_uv0.x - uvOffset.x) / (uvOffset.z - uvOffset.x);
  float uv0Y = (v_uv0.y - uvOffset.y) / (uvOffset.w - uvOffset.y);
  vec2 uv0 = rotated > 0.5 ? vec2(uv0Y, 1.0 - uv0X) : vec2(uv0X, uv0Y);
  if (abs(angle) < 0.7853981633974483) {
    float slope = tan(angle);
    float minVal = -slope * uv0.y - width + startx * (slope + 1.0 + 2.0 * width);
    float maxVal = -slope * uv0.y - width + startx * (slope + 1.0 + 2.0 * width) + width;
    float midVal = (minVal + maxVal) * 0.5;
    float gapVal = (maxVal - minVal) * 0.5;
    if (uv0.x > minVal && uv0.x < maxVal) {
      float opacity = 1.0 - abs(uv0.x - midVal) / gapVal;
      outColor.a *= opacity * strength;
    } else {
      outColor.a = 0.;
    }
  } else {
    float slope = tan(0.7853981633974483 * 2.0 - angle);
    float minVal = -slope * uv0.x - width + startx * (slope + 1.0 + 2.0 * width);
    float maxVal = -slope * uv0.x - width + startx * (slope + 1.0 + 2.0 * width) + width;
    float midVal = (minVal + maxVal) * 0.5;
    float gapVal = (maxVal - minVal) * 0.5;
    if (uv0.y > minVal && uv0.y < maxVal) {
      float opacity = 1.0 - abs(uv0.y - midVal) / gapVal;
      outColor.a *= opacity * strength;
    } else {
      outColor.a = 0.;
    }
  }
  gl_FragColor = outColor;
}

